# likelihood_terms ----
## Setup ----
# Load or prepare any necessary data for testing

## IO correctness ----
test_that("likelihood-term helpers work with correct inputs", {
  #' @description Test that likelihood-term helpers wrap the Rcpp model controls.
  model <- methods::new(CatchAtAge)

  expect_false(uses_likelihood_terms(model))
  expect_identical(use_likelihood_terms(model), model)
  expect_true(uses_likelihood_terms(model))
  expect_identical(use_likelihood_terms(model, FALSE), model)
  expect_false(uses_likelihood_terms(model))

  terms <- get_likelihood_terms(model)
  expect_s3_class(terms, "data.frame")
  expect_equal(names(terms), c("name", "type", "source_id"))
  expect_equal(nrow(terms), 0L)

  clear()
})

## Edge handling ----
test_that("likelihood-term helpers return correct outputs for edge cases", {
  #' @description Test that likelihood-term helpers validate logical inputs.
  model <- methods::new(CatchAtAge)

  expect_error(
    use_likelihood_terms(model, NA),
    regexp = "`value` must be TRUE or FALSE"
  )
  expect_error(
    use_likelihood_terms(model, c(TRUE, FALSE)),
    regexp = "`value` must be TRUE or FALSE"
  )

  clear()
})

## Error handling ----
test_that("likelihood-term helpers return correct error messages", {
  #' @description Test that likelihood-term helpers require supported model objects.
  expect_error(
    uses_likelihood_terms("not a model"),
    regexp = "`model` does not support mirrored likelihood-term controls"
  )
  expect_error(
    get_likelihood_terms(methods::new(DnormDistribution)),
    regexp = "`model` does not support mirrored likelihood-term controls"
  )

  clear()
})
